import React, {Component} from "react";
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import {faAlignLeft} from '@fortawesome/free-solid-svg-icons';
import { faTimes } from '@fortawesome/free-solid-svg-icons';
import footer from "../test/arm.png";

class Menu extends Component{
    render() {
        return(
            <div className={this.props.info.class}>
                <div className="console">
                    <h3>Menu</h3>
                    <button onClick={ this.props.onClick } type="button" className="btn btn-light">
                        <FontAwesomeIcon icon={faTimes}/>
                    </button>
                </div>
                <ul>
                    <li>
                        <a href="#"><FontAwesomeIcon icon={faAlignLeft}/> item1</a>
                    </li>
                    <li>
                        <a href="#"><FontAwesomeIcon icon={faAlignLeft}/> item2</a>
                    </li>
                    <li>
                        <a href="#"><FontAwesomeIcon icon={faAlignLeft}/> item3</a>
                    </li>
                    <li>
                        <a href="#"><FontAwesomeIcon icon={faAlignLeft}/> item4</a>
                    </li>
                    <li>
                        <a href="#"><FontAwesomeIcon icon={faAlignLeft}/> item5</a>
                    </li>
                </ul>
                <div className="footer">
                    <img src={ footer } alt="footer"/>
                </div>
            </div>
        );
    }
}

export default Menu;