import React, {Component} from "react";
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import {faTimes} from '@fortawesome/free-solid-svg-icons';
class Menu extends Component{
    renderOptions(){
        if (this.props.info.options){
            return(
                <div className="options">
                    {
                        this.props.info.options.map(opt =>{
                            return(
                                <a href="#">
                                    <div className="image"><img src={ this.props.info.image_url } alt="option"/></div>
                                    <div className="price"><span>{ opt.price }</span></div>
                                </a>
                            );
                        })
                    }
                </div>
            );
        }
    }

    render() {
        return(
            <div className={ this.props.info.class }>
                <div className="title_image">
                    <div className="top_image">
                        <img loading="lazy" src={ this.props.info.image_url } alt={ this.props.info.image_alt }/>
                    </div>
                    <div className="detail">
                        <div className="section">
                            <div className="main">
                                <a href="">
                                    <div className="image"><img loading="lazy" src={ this.props.info.image_url } alt="option"/></div>
                                    <div className="price"><span>{ this.props.info.price }</span></div>
                                </a>
                            </div>
                            { this.renderOptions() }
                        </div>
                    </div>
                </div>
                <button onClick={ () => this.props.onClick() } type="button" className="btn btn-light">
                    <FontAwesomeIcon icon={faTimes}/>
                </button>
            </div>
        );
    }
}

export default Menu;